INSERT INTO `ruoli` (`IDRuolo`, `nomeRuolo`, `descrizione`) VALUES
(1, 'altro', 'Da usare quando tra le voci elencate non esiste il ruolo specifico'),
(2, 'capo ufficio', ''),
(3, 'capo reparto', ''),
(4, 'impiegato/a', ''),
(5, 'project manager', ''),
(6, 'Amministratore delegato (CEO)', 'È la persona maggiormente responsabile della gestione e dell\'amministrazione dell\'azienda. In parole povere, è il CEO che gestisce, amministra e dà indicazioni sulla direzione da prendere all\'azienda. Il modo ideale per adempiere a questa funzione è l\'att'),
(7, 'direttore operativo', 'Chi controlla il funzionamento del sistema di creazione e distribuzione dei prodotti dell\'azienda. È responsabile dell\'attuazione dei piani strategici e di garantire che l\'azienda raggiunga i propri obiettivi nei tempi e nei costi previsti.'),
(8, 'direttore commerciale', 'È la posizione più alta all\'interno del reparto vendite e la sua funzione principale è quella di attuare piani di vendita allineati agli obiettivi e alla visione della pianificazione strategica. Se un\'azienda ha diversi venditori, è responsabilità del dir'),
(9, 'marketing manager', 'Gestisce gli aspetti relativi al prodotto, ai prezzi, al mercato e alla promozione. È uno dei ruoli indispensabili in un\'azienda.'),
(10, 'responsabile delle risorse umane', 'All\'interno di un\'azienda non esistono solo i prodotti, ma è necessario occuparsi del benessere del personale allo stesso modo in cui ci si preoccupa delle vendite. È proprio questo l\'obiettivo di quest\'area.'),
(11, 'customer satisfaction', 'Lavora per garantire che i clienti utilizzino il prodotto o il servizio in maniera proficua, per fidelizzarli mantenendoli attivi e raggiungere gli obiettivi prefissati.'),
(12, 'responsabile finanziario', 'Pianifica le strategie di investimento e di gestione dei fondi, nonché le strategie future dell\'azienda. Indipendentemente dalle dimensioni o dalla situazione di un\'azienda, questa ha bisogno di uno specialista in finanza.'),
(13, 'proprietario/a', 'Titolare dell\'azienda o socio'),
(14, 'operaio/a', 'Operaio normale'),
(15, 'operaio/a specializzato/a', 'operaio con esperienza e competenza riconosciuta'),
(16, 'ufficio tecnico', ''),
(17, 'ufficio CED', 'Responsabile rete informatica e dei computer'),
(18, 'RSPP', ''),
(19, 'ASPP', '');
