(2, 'Docente', 'Ruolo da assegnare agli insegnanti che partecipano ad un\'assemblea sorvegliando un\'attività.'),
(3, 'Esterno', 'Ruolo da assegnare a presonale esterno che partecipa ad un\'attività di presentazione all\'interno dell\'assemblea.'),
(6, 'Test', 'Test'),
(10, 'Giocatore', 'Test per giocatori di pallavolo');
