INSERT INTO `tickets` (`IDTicket`, `descrizioneProblemaTicket`, `idTipoTicket`, `idDispositivo`, `idAmbiente`, `idUtenteCreazione`, `percorsoFoto`, `stato`, `TSsegnalazione`, `idTecnicoPresaInCarico`, `TSpresaInCarico`, `noteIntervento`, `TSchiusuraTicket`, `mailTicket`) VALUES
(51, 'Si accende Spia Verde ma schermo resta nero', 8, 11, 1, 1391, NULL, '4', '2025-08-25 10:16:13.000000', 1391, '2025-08-25 10:17:19.000000', '2025-08-25 12:17\nda spedire in assistenza perchè in garanzia\n\n', NULL, b'1'),
(52, 'Digital Board si accende però rimane sulla scritta Yashi... Provato più volte a riavviarla..... Provato a resettarla con chiavetta e filmware ma non ci siamo riusciti', 8, 12, 78, 1391, NULL, '4', '2025-08-26 05:32:50.000000', 1391, '2025-09-18 09:19:16.000000', NULL, NULL, b'0'),
(53, 'Digital Board si accende però rimane sulla scritta Yashi... Provato più volte a riavviarla..... Provato a resettarla con chiavetta e filmware ma non ci siamo riusciti', 8, 12, 78, 1391, NULL, '4', '2025-08-26 05:32:51.000000', 1391, '2025-09-18 09:19:03.000000', NULL, NULL, b'0'),
(54, 'Si accende ma schermo tutto nero... Provato più soluzioni senza risultato', 7, 13, 85, 1391, NULL, '4', '2025-08-26 05:38:07.000000', 1391, '2025-09-18 09:18:41.000000', NULL, NULL, b'1'),
(55, 'Su Google Chrome sarebbe meglio aggiornare l\'estensione\r\nGeogebra classico.\r\nIn caso non fosse possibile è opportuno togliere la vecchia versione per evitare il fastidioso messaggio (come da allegato) che si presenta ad ogni avvio', 7, NULL, 141, 2071, 'fotoTicket/ticket55.png', '3', '2025-09-12 10:06:28.000000', 1391, '2025-09-13 10:11:42.000000', '2025-09-13 12:13\nIn che pc è stato segnalato il problema?\r\nVisto che abbiamo più dispositivi e con programmi e aggiornamenti diversi\n\n2025-09-15 13:00\nIl computer in questione è del docente.\r\nNoi non possiamo intervenire\n\n', '2025-09-15 11:00:52.000000', b'0'),
(56, 'Tasto \'@\' non funzionante (postazione A20)', 7, NULL, 78, 2053, NULL, '3', '2025-09-20 11:00:30.000000', 1391, '2025-09-25 10:43:53.000000', '2025-09-25 12:46\nA volte non funziona il tasto @ semplicemente xchè si sta usando tastiera in INGLESE.... windows durante aggiornamenti mette tastiera predefinita in inglese \r\nSi deve guardare in basso a dx del monitor se c\'è IT \n\n', '2025-09-25 10:47:18.000000', b'1'),
(57, 'Ultima fila di dx: è stato modificato il desktop dei pc;\r\nPostazione A-019: tasto rotto \'H\'', 7, NULL, 78, 2053, NULL, '3', '2025-09-23 09:27:38.000000', 1391, '2025-09-25 11:00:00.000000', '2025-09-25 13:04\nHo controllato\r\nC\'erano i tasti H e F invertiti\r\nLi ho sistemati e rimessi al loro posto\n\n', '2025-09-25 11:04:44.000000', b'1'),
(58, 'Tasti (fisici) corretti, ma quando digitati il simbolo/valore è errato - PC A20', 7, NULL, 78, 2053, NULL, '3', '2025-10-01 09:41:37.000000', 1391, '2025-10-07 10:55:25.000000', '2025-10-07 13:24\nCome già riferito a voce. L\'aggiornamento di Windows porta il computer ad usare tastiera inglese che ha i tasti posizionati in modo diverso da quella italiana. Ho descritto problema in modo che se capita anche ad altri questa è la soluzione, cambiare tastiera in modalità ITA\n\n', '2025-10-07 11:24:11.000000', b'1'),
(59, 'Cavo HDMI danneggiato, monitor non funziona- pc A019', 7, NULL, 78, 2053, NULL, '3', '2025-10-18 06:02:11.000000', 1391, '2025-10-18 07:25:24.000000', '2025-10-18 09:26\nCambiato cavo HDMI con cavo VGA\r\nProblema risolto\n\n', '2025-10-18 07:26:44.000000', b'1');
